import numpy as np

class StandardScaler:
    def __init__(self):
        self.mean_ = None
        self.std_ = None

    def fit(self, X):
        self.mean_ = X.mean(axis=0)
        self.std_ = X.std(axis=0) + 1e-8
        return self

    def transform(self, X):
        return (X - self.mean_) / self.std_

    def fit_transform(self, X):
        return self.fit(X).transform(X)


class PCA:
    def __init__(self, n_components=2):
        self.n_components = n_components
        self.components_ = None
        self.mean_ = None
        self.explained_variance_ratio_ = None

    def fit(self, X):
        self.mean_ = X.mean(axis=0)
        X_c = X - self.mean_
        cov = np.cov(X_c, rowvar=False)
        if cov.ndim == 0:
            cov = np.array([[float(cov)]])
        eigvals, eigvecs = np.linalg.eigh(cov)
        idx = np.argsort(eigvals)[::-1]
        eigvals = eigvals[idx]
        eigvecs = eigvecs[:, idx]
        self.components_ = eigvecs[:, :self.n_components].T
        total_var = eigvals.sum() + 1e-10
        self.explained_variance_ratio_ = eigvals[:self.n_components] / total_var
        return self

    def transform(self, X):
        return (X - self.mean_) @ self.components_.T

    def fit_transform(self, X):
        return self.fit(X).transform(X)


class KMeansPlusPlus:
    def __init__(self, n_clusters, max_iter=300, tol=1e-4, random_state=None):
        self.n_clusters = n_clusters
        self.max_iter = max_iter
        self.tol = tol
        self.rng = np.random.RandomState(random_state)
        self.centroids_ = None
        self.labels_ = None
        self.inertia_ = None

    def _init_centroids(self, X):
        n = X.shape[0]
        # Choose first centroid randomly
        idx = self.rng.randint(0, n)
        centroids = [X[idx]]
        for _ in range(1, self.n_clusters):
            # Compute distance squared to nearest centroid
            dists = np.array([
                min(np.sum((x - c)**2) for c in centroids)
                for x in X
            ])
            probs = dists / (dists.sum() + 1e-10)
            idx = self.rng.choice(n, p=probs)
            centroids.append(X[idx])
        return np.array(centroids)

    def _assign(self, X, centroids):
        # Vectorized assignment
        dists = np.sum((X[:, None, :] - centroids[None, :, :]) ** 2, axis=2)
        return np.argmin(dists, axis=1)

    def fit(self, X):
        self.centroids_ = self._init_centroids(X)
        for _ in range(self.max_iter):
            labels = self._assign(X, self.centroids_)
            new_centroids = np.zeros_like(self.centroids_)
            for k in range(self.n_clusters):
                mask = labels == k
                if mask.sum() > 0:
                    new_centroids[k] = X[mask].mean(axis=0)
                else:
                    new_centroids[k] = self.centroids_[k]
            shift = np.max(np.linalg.norm(new_centroids - self.centroids_, axis=1))
            self.centroids_ = new_centroids
            if shift < self.tol:
                break
        self.labels_ = self._assign(X, self.centroids_)
        dists = np.sum((X - self.centroids_[self.labels_]) ** 2, axis=1)
        self.inertia_ = float(dists.sum())
        return self

    def predict(self, X):
        return self._assign(X, self.centroids_)


def silhouette_score(X, labels):
    n = len(X)
    unique_labels = np.unique(labels)
    if len(unique_labels) < 2:
        return 0.0
    scores = np.zeros(n)
    for i in range(n):
        same_mask = (labels == labels[i])
        same_mask[i] = False
        if same_mask.sum() == 0:
            scores[i] = 0.0
            continue
        a_i = np.mean(np.linalg.norm(X[same_mask] - X[i], axis=1))
        b_i = np.inf
        for other_label in unique_labels:
            if other_label == labels[i]:
                continue
            other_mask = (labels == other_label)
            mean_dist = np.mean(np.linalg.norm(X[other_mask] - X[i], axis=1))
            b_i = min(b_i, mean_dist)
        denom = max(a_i, b_i)
        scores[i] = (b_i - a_i) / denom if denom > 1e-10 else 0.0
    return float(np.mean(scores))


class ClusterPipeline:
    def __init__(self, n_components=2, random_state=42):
        self.scaler = StandardScaler()
        self.pca = PCA(n_components=n_components)
        self.kmeans = None
        self.n_components = n_components
        self.random_state = random_state
        self._X_pca = None
        self._labels = None

    def fit_predict(self, X, n_clusters):
        X_scaled = self.scaler.fit_transform(X)
        self._X_pca = self.pca.fit_transform(X_scaled)
        self.kmeans = KMeansPlusPlus(
            n_clusters=n_clusters,
            random_state=self.random_state
        )
        self.kmeans.fit(self._X_pca)
        self._labels = self.kmeans.labels_
        return self._labels

    def evaluate(self):
        if self._X_pca is None or self._labels is None:
            raise RuntimeError('Call fit_predict first')
        return silhouette_score(self._X_pca, self._labels)
